import React, { useState, useEffect, useRef } from "react";
import "./generalchat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
    },
  ]);

  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  // Auto-scroll to latest message
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Therapist-style reply logic
  const getTherapistReply = (userText) => {
    const text = userText.toLowerCase();

    if (text.includes("exhaust") || text.includes("tired")) {
      return "That sounds really draining. You’ve been carrying a lot. Have you been able to rest properly lately? 💜";
    }

    if (text.includes("sad") || text.includes("low")) {
      return "I hear you. Feeling sad can feel heavy inside. Do you want to talk about what’s been making you feel this way?";
    }

    if (text.includes("lonely") || text.includes("alone")) {
      return "Feeling lonely can hurt deeply, even when people are around. I’m really glad you reached out 🤍";
    }

    if (text.includes("stress") || text.includes("pressure")) {
      return "That sounds overwhelming. Let’s slow things down for a moment. What’s causing the most pressure right now?";
    }

    if (text.includes("anxious") || text.includes("anxiety")) {
      return "Anxiety can make everything feel intense. Try taking one slow breath with me. What’s making you feel anxious?";
    }

    if (text.includes("angry") || text.includes("frustrated")) {
      return "It sounds like there’s a lot of frustration built up. That’s completely valid. What triggered it?";
    }

    return "I’m here with you 💜 Take your time. Would you like to tell me more about what’s been on your mind?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = {
      sender: "user",
      text: input,
    };

    const botMessage = {
      sender: "bot",
      text: getTherapistReply(input),
    };

    setMessages((prev) => [...prev, userMessage, botMessage]);
    setInput("");
  };

  return (
    <div className="chat-page">
      <h2 className="chat-title">🧠 General Chat</h2>

      <div className="chat-container">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`chat-bubble ${msg.sender === "user" ? "user" : "bot"}`}
          >
            {msg.sender === "bot" && (
              <div className="bot-label">💖 Listening</div>
            )}
            <div className="chat-text">{msg.text}</div>
          </div>
        ))}
        <div ref={chatEndRef}></div>
      </div>

      <div className="chat-input-area">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
